// ─── Utility: filter variable_inputs grid to show only rows for a given test row ───
function filter_variable_inputs(frm, parent_test_row_name) {
    frm.fields_dict['variable_inputs'].grid.get_rows().forEach(grid_row => {
        let row_data = grid_row.doc;
        if (row_data.parent_test_row === parent_test_row_name) {
            $(grid_row.wrapper).show();
        } else {
            $(grid_row.wrapper).hide();
        }
    });
}

// ─── Safe removal of all variable_input child rows tied to a specific test row ───
function clear_variables_for_test_row(frm, test_row_name) {
    // Collect names to remove first, then remove — avoids index-shift bugs
    let names_to_remove = (frm.doc.variable_inputs || [])
        .filter(v => v.parent_test_row === test_row_name)
        .map(v => v.name);

    names_to_remove.forEach(name => {
        let idx = (frm.doc.variable_inputs || []).findIndex(v => v.name === name);
        if (idx !== -1) {
            frm.doc.variable_inputs.splice(idx, 1);
        }
    });

    // Rebuild the grid cleanly
    frm.refresh_field('variable_inputs');
}

// ─── Main child table handler ───
frappe.ui.form.on('Soil Test Result Entry', {

    test_item: function(frm, cdt, cdn) {
        let d = locals[cdt][cdn];
        if (!d.test_item) return;

        frappe.db.get_doc('Soil Test Package', d.test_item).then(master => {

            // ── CASE 1: This is a Package (container) — explode into sub-tests ──
            if (master.included_tests && master.included_tests.length > 0) {
                master.included_tests.forEach(sub => {
                    let new_row = frm.add_child('results_table');
                    frappe.model.set_value(
                        new_row.doctype, new_row.name,
                        'test_item', sub.linked_package
                    );
                });
                // Remove the container row itself
                frappe.model.clear_doc(cdt, cdn);
                frm.refresh_field('results_table');
                return; // Stop here for package rows
            }

            // ── CASE 2: Single test — set formula & unit ──
            frappe.model.set_value(cdt, cdn, 'formula', master.formula);
            frappe.model.set_value(cdt, cdn, 'base_unit', master.target_unit);

            // ── KEY FIX: Reliably wipe only THIS row's variables before re-adding ──
            clear_variables_for_test_row(frm, d.name);

            // ── Add fresh variables from the master ──
            if (master.variable_table && master.variable_table.length > 0) {
                master.variable_table.forEach(v => {
                    let var_row = frm.add_child('variable_inputs');
                    // Set directly on the doc object to avoid triggering extra events
                    var_row.variable_key   = v.variable_key;
                    var_row.description    = v.label;
                    var_row.parent_test_row = d.name;
                    var_row.test_item      = d.test_item;
                    var_row.value          = v.default_value || '';
                });
            }

            frm.refresh_field('variable_inputs');
            filter_variable_inputs(frm, d.name);
        });
    },

    form_render: function(frm, cdt, cdn) {
        let d = locals[cdt][cdn];
        filter_variable_inputs(frm, d.name);
    }
});

frappe.ui.form.on('Soil Sample Collection', {

    onload: function(frm) {

        // Existing document → do nothing (show saved values)
        if (!frm.is_new()) {
            return;
        }

        set_employee_fields(frm);
    }

});


function set_employee_fields(frm) {

    // Hide first
    frm.toggle_display("employee_type", false);
    frm.toggle_display("lab_name", false);
    frm.toggle_display("district_office_name", false);

    // Admin / MD bypass
    if (
        frappe.session.user === "Administrator" ||
        frappe.user.has_role("Managing Director")
    ) {
        return;
    }

    frappe.call({
        method: "frappe.client.get_value",
        args: {
            doctype: "Employee",
            filters: { user_id: frappe.session.user },
            fieldname: [
                "employment_type",
                "custom_lab_name",
                "custom_district_office_name"
            ]
        },
        callback(r) {

            if (!r.message) return;

            const emp_type = r.message.employment_type;

            frm.set_value("employee_type", emp_type);
            frm.toggle_display("employee_type", true);

            if (emp_type === "Lab") {

                frm.set_value("lab_name", r.message.custom_lab_name);
                frm.toggle_display("lab_name", true);

            } else if (emp_type === "District Office") {

                frm.set_value(
                    "district_office_name",
                    r.message.custom_district_office_name
                );

                frm.toggle_display("district_office_name", true);
            }
        }
    });
}

frappe.ui.form.on('Employee', {
    refresh(frm) {
        toggle_employee_fields(frm);
    },
    employment_type(frm) {
        toggle_employee_fields(frm);
    }
});

function toggle_employee_fields(frm) {

    if (frm.doc.employment_type === "Lab") {

        // Show Lab field
        frm.toggle_display('custom_lab_name', true);
        frm.toggle_display('custom_district_office_name', false);

        // Mandatory rules
        frm.toggle_reqd('custom_lab_name', true);
        frm.toggle_reqd('custom_district_office_name', false);

    } else if (frm.doc.employment_type === "District Office") {

        // Show District Office field
        frm.toggle_display('custom_lab_name', false);
        frm.toggle_display('custom_district_office_name', true);

        // Mandatory rules
        frm.toggle_reqd('custom_lab_name', false);
        frm.toggle_reqd('custom_district_office_name', true);

    } else {

        // Hide both if nothing selected
        frm.toggle_display('custom_lab_name', false);
        frm.toggle_display('custom_district_office_name', false);
    }
}

frappe.ui.form.on("ToDo", {

    before_save(frm) {

        // 🔴 Cancel Reason Mandatory
        if (frm.doc.status === "Cancelled") {
            if (!frm.doc.custom_cancel_reason) {
                frappe.throw("Cancel Reason is mandatory when cancelling.");
            }
        }

        // 🟢 Auto Fill Completed Date
        if (frm.doc.status === "Closed") {
            if (!frm.doc.custom_completed_date) {
                frm.set_value("custom_completed_date", frappe.datetime.get_today());
            }
        }

        // 🔄 Clear completed date ONLY if reopened
        if (
            frm.doc.status === "Open" &&
            frm.doc.custom_completed_date &&
            frm.doc.__unsaved
        ) {
            frm.set_value("custom_completed_date", null);
        }
    }
});

frappe.ui.form.on('Soil Sample Collection', {

    refresh(frm) {
        toggle_field(frm);
    },

    status(frm) {
        toggle_field(frm);
    }

});

function toggle_field(frm) {
    if (frm.doc.status === "Enter File number") {
        frm.set_df_property("file_number", "hidden", 0);
        frm.set_df_property("file_number", "reqd", 1);
    } else {
        frm.set_df_property("file_number", "hidden", 1);
        frm.set_df_property("file_number", "reqd", 0);
    }
}

frappe.ui.form.on('Soil Sample Collection', {

    refresh(frm) {
        toggle_fields(frm);
    },

    status(frm) {
        toggle_fields(frm);
    }

});

function toggle_fields(frm) {

    frm.toggle_display("completed_date", frm.doc.status === "completed");

    if (frm.doc.status === "completed") {
        frm.toggle_display("return_to_sc_date", false);
        frm.toggle_display("return_to_psc_date", false);
    } else {
        frm.toggle_display("return_to_sc_date", true);
        frm.toggle_display("return_to_psc_date", true);
    }

}

frappe.ui.form.on("Monthly Target", {

    refresh(frm){

        // Always remove old button and re-add
        frm.clear_custom_buttons();

        frm.add_custom_button("Calculate Target", () => {

            if(frm.is_new()){
                frm.save().then(() => {
                    run_calculation(frm);
                });
            }else{
                run_calculation(frm);
            }

        });

    }

});


function run_calculation(frm){

    frappe.call({
        method: "slis_app.api.Monthly_Target.calculate_target",
        args:{
            docname: frm.doc.name
        },
        callback(){
            frm.reload_doc();
        }
    });

}



frappe.ui.form.on("Lab Target", {

    month(frm, cdt, cdn){

        let row = locals[cdt][cdn];

        if(!row.month) return;

        let duplicate = false;

        frm.doc.lab_target.forEach(function(d){

            if(d.name != row.name && d.month == row.month){
                duplicate = true;
            }

        });

        if(duplicate){

            frappe.msgprint("Target for this month already exists");

            frappe.model.set_value(cdt, cdn, "month", "");

        }

    },


    lab_target_add(frm, cdt, cdn){

        frappe.call({
            method:"frappe.client.get_value",
            args:{
                doctype:"Employee",
                filters:{user_id:frappe.session.user},
                fieldname:["custom_lab_name"]
            },
            callback(r){

                if(r.message){
                    frappe.model.set_value(cdt, cdn, "lab_name", r.message.custom_lab_name);
                }

            }
        });

    }

});

frappe.listview_settings['Register'] = {
    onload: function(listview) {

        listview.page.add_inner_button("Bulk Entry", function() {

            let selected = listview.get_checked_items();

            if (selected.length === 0) {
                frappe.msgprint("Select samples first");
                return;
            }

            // 🔹 Step 1: SORT
            selected.sort((a, b) => {
                let numA = parseInt(a.name.split('-').pop());
                let numB = parseInt(b.name.split('-').pop());
                return numA - numB;
            });

            // 🔹 Step 2: Fetch all Register docs
            let promises = selected.map(item => {
                return frappe.db.get_doc('Register', item.name);
            });

            Promise.all(promises).then(docs => {

                // 🔹 Step 3: Validate Client Type = Department
                let invalid = docs
                    .filter(d => d.client_type !== "Department")
                    .map(d => d.name);

                if (invalid.length > 0) {
                    frappe.msgprint(
                        "Only Department samples are allowed:<br>" + invalid.join("<br>")
                    );
                    return;
                }

                // 🔹 Step 4: Validate same scheme
                let schemes = [...new Set(docs.map(d => d.scheme_name))];

                if (schemes.length > 1) {
                    frappe.msgprint("All selected records must have the same Scheme");
                    return;
                }

                // 🔹 Step 5: Create Bulk Entry
                frappe.model.with_doctype('Bulk Test Entry', function() {

                    let doc = frappe.model.get_new_doc('Bulk Test Entry');

                    // Set scheme
                    doc.scheme = schemes[0];

                    // 🔹 Add rows
                    selected.forEach(item => {
                        let row = frappe.model.add_child(doc, 'bulk_test_entry_item');
                        row.register_id = item.name;
                    });

                    frappe.set_route('Form', 'Bulk Test Entry', doc.name);

                });

            });

        });

    }
};

frappe.ui.form.on('Bulk Test Entry', {
    scheme: function(frm) {
        if (frm.doc.scheme) {
            frappe.db.get_doc('Scheme', frm.doc.scheme).then(scheme_doc => {
                let grid = frm.fields_dict['bulk_items'].grid;

                // Reset all labels first
                for (let i = 1; i <= 12; i++) {
                    grid.update_docfield_property('v' + i, 'label', 'Value ' + i);
                    grid.update_docfield_property('v' + i, 'hidden', 1);
                }

                // Apply Scheme labels
                scheme_doc.scheme_test_list.forEach((test, index) => {
                    let fieldname = "v" + (index + 1);
                    grid.update_docfield_property(fieldname, 'label', test.test_item);
                    grid.update_docfield_property(fieldname, 'hidden', 0);
                });
                frm.refresh_field('bulk_items');
            });
        }
    }
});

