frappe.ui.form.on('Register', {
    refresh: function(frm) {
        if (!frm.is_new()) {

            frm.add_custom_button(__('Move to Test'), function() {

                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "Soil Test Result",
                        filters: {
                            sample_id: frm.doc.name
                        },
                        fields: ["name"],
                        limit_page_length: 1
                    },
                    callback: function(r) {

                        if (r.message && r.message.length > 0) {
                            // Already exists → Open it
                            frappe.set_route('Form', 'Soil Test Result', r.message[0].name);

                        } else {
                            // Not exists → Create new
                            frappe.new_doc('Soil Test Result', {
                                sample_id: frm.doc.name
                            });
                        }

                    }
                });

            }, __("Actions"));
        }
    }
});

