frappe.listview_settings['Soil Sample Collection'] = {
    onload: function(listview) {

        listview.page.add_inner_button("Bulk Test Entry", function() {

            let selected = listview.get_checked_items();

            if (selected.length === 0) {
                frappe.msgprint("Please select samples");
                return;
            }

            let valid_samples = [];

            // 🔹 Step 1: Fetch docs
            let promises = selected.map(item => {
                return frappe.db.get_doc('Soil Sample Collection', item.name)
                    .then(doc => {
                        if (doc.client_type === "Department") {
                            valid_samples.push(doc);
                        }
                    });
            });

            Promise.all(promises).then(() => {

                if (valid_samples.length === 0) {
                    frappe.msgprint("Only Department samples are allowed");
                    return;
                }

                // 🔹 Step 2: Validate same scheme
                let schemes = [...new Set(valid_samples.map(d => d.scheme_name))];

                if (schemes.length > 1) {
                    frappe.msgprint("All selected samples must have the same Scheme");
                    return;
                }

                // 🔹 Step 3: Check duplication
                let check_promises = valid_samples.map(doc => {
                    return frappe.db.get_list('Bulk Test Entry Item', {
                        filters: {
                            register_id: doc.name
                        },
                        fields: ['name'],
                        limit: 1
                    }).then(r => {
                        return r.length > 0 ? doc.name : null;
                    });
                });

                Promise.all(check_promises).then(results => {

                    let duplicates = results.filter(r => r);

                    if (duplicates.length > 0) {
                        frappe.msgprint(
                            "Already exists in Bulk Entry:<br>" + duplicates.join("<br>")
                        );
                        return;
                    }

                    // 🔹 Step 4: SORT
                    valid_samples.sort((a, b) => a.name.localeCompare(b.name));

                    // 🔹 Step 5: Create Bulk Entry
                    frappe.model.with_doctype('Bulk Test Entry', function() {

                        let new_doc = frappe.model.get_new_doc('Bulk Test Entry');

                        // set scheme
                        new_doc.scheme = schemes[0];

                        // 🔹 Add child rows
                        valid_samples.forEach(doc => {
                            let row = frappe.model.add_child(new_doc, 'bulk_test_entry_item');
                            row.register_id = doc.name;
                        });

                        frappe.set_route('Form', 'Bulk Test Entry', new_doc.name);

                    });

                });

            });

        });

    }
};

frappe.ui.form.on('Bulk Test Entry', {
    scheme: function(frm) {
        if (!frm.doc.scheme) return;

        // Fetch formulas and variables from the linked Packages
        frappe.call({
            method: "frappe.client.get_value",
            args: {
                doctype: "Scheme",
                filters: { name: frm.doc.scheme },
                fieldname: "name" 
            },
            callback: function() {
                // Logic to map v1...v30 to Package variables
                setup_bulk_grid(frm);
            }
        });
    }
});

// Helper to rename columns
function setup_bulk_grid(frm) {
    let grid = frm.fields_dict['bulk_items'].grid;
    // Reset all
    for (let i = 1; i <= 30; i++) grid.update_docfield_property('v' + i, 'hidden', 1);

    // This part requires fetching the Child Table of the Scheme 
    // to get the linked 'Soil Test Packages'
    frappe.db.get_doc('Scheme', frm.doc.scheme).then(scheme => {
        let v_ptr = 1;
        scheme.scheme_test_list.forEach(item => {
            frappe.db.get_doc('Soil Test Package', item.test_package).then(pkg => {
                let vars = pkg.variables.split(',');
                vars.forEach(v => {
                    grid.update_docfield_property('v' + v_ptr, 'label', pkg.test_name + ": " + v.trim());
                    grid.update_docfield_property('v' + v_ptr, 'hidden', 0);
                    v_ptr++;
                });
                // Result Column
                grid.update_docfield_property('v' + v_ptr, 'label', pkg.test_name + " (RES)");
                grid.update_docfield_property('v' + v_ptr, 'hidden', 0);
                grid.update_docfield_property('v' + v_ptr, 'read_only', 1);
                v_ptr++;
            });
        });
        frm.refresh_field('bulk_items');
    });
}

