frappe.ui.form.on('Soil Sample Collection', {

    refresh(frm) {

        (frm.doc.tests || []).forEach(row => {

            if (row.test_name) {

                frappe.db.get_doc('Soil Test Package', row.test_name)
                    .then(doc => {

                        row.parameter_count = doc.parameter_count || 0;
                        frm.refresh_field('tests');

                        // 🔥 update total
                        calculate_total(frm);

                    });

            }

        });

    },

    // ✅ when row added
    tests_add(frm) {
        calculate_total(frm);
    },

    // ✅ when row removed
    tests_remove(frm) {
        calculate_total(frm);
    }

});


// ===============================
// 🔥 MAIN FUNCTION (FETCH COUNT)
// ===============================
function set_parameter_count(frm, cdt, cdn) {

    let row = locals[cdt][cdn];

    if (!row.test_name) return;

    frappe.db.get_doc('Soil Test Package', row.test_name)
        .then(doc => {

            let count = doc.parameter_count || 0;

            frappe.model.set_value(
                cdt,
                cdn,
                'parameter_count',
                count
            );

        });

}


// ===============================
// 🔥 TOTAL CALCULATION
// ===============================
function calculate_total(frm) {

    let total = 0;

    (frm.doc.tests || []).forEach(row => {

        if (row.parameter_count) {
            total += row.parameter_count;
        }

    });

    frm.set_value('total_parameter_count', total);
}

