    results_table_on_form_render(frm, cdt, cdn) {

        let row = locals[cdt][cdn];

        frm.doc.current_active_test = row.name;

        apply_filter(frm, row.name);

    }

});


function apply_filter(frm, test_id) {

    if (!frm.fields_dict.variable_inputs) return;

    let grid = frm.fields_dict.variable_inputs.grid;

    grid.grid_rows.forEach(row => {

        if (!test_id) {
            row.wrapper.show();
            return;
        }

        row.wrapper.toggle(row.doc.parent_test_row === test_id);

    });

}

