        control_reason_visibility(frm);
    },

    before_workflow_action(frm) {

        const action = frm.selected_workflow_action;

        if (
            action === "Send Back" &&
            frm.doc.status === "With Senior Chemist" &&
            !frm.doc.send_back_reason
        ) {
            frappe.throw("Send Back Reason is mandatory");
        }
    }

});


// 🔵 Store original lab when PSC first receives
function store_psc_lab(frm) {

    if (
        frm.doc.status === "With PSC Officer" &&
        !frm.doc.psc_entry_target_lab &&
        !frm.is_new()        // important
    ) {
        frm.set_value(
            "psc_entry_target_lab",
            frm.doc.target_lab
        );
    }
}


// 🔵 Control visibility
function control_reason_visibility(frm) {

    const status = frm.doc.status;
    const original_lab = frm.doc.psc_entry_target_lab;
    const current_lab = frm.doc.target_lab;

    frm.toggle_display("send_back_reason", false);

    if (
        status === "With PSC Officer" &&
        original_lab &&
        current_lab &&
        original_lab !== current_lab
    ) {
        return;
    }

    const visible_status = [
        "With Senior Chemist",
        "Returned to Senior Chemist(Overload)",
        "Returned to PSC (Overload)"
    ];

    if (visible_status.includes(status)) {
        frm.toggle_display("send_back_reason", true);
    }
}

