function toggle_local_body_fields(frm) {
    let type = frm.doc.local_body_type;

    // Show/Hide fields based on selection
    // Syntax: frm.set_df_property(field_name, property, value)

    frm.set_df_property('municipality', 'hidden', type !== 'Municipality');
    frm.set_df_property('corporation', 'hidden', type !== 'Corporation');
    frm.set_df_property('panchayath', 'hidden', type !== 'Panchayath');

    // Optional: Clear the values of hidden fields so you don't save 
    // data in the wrong field by mistake.
    if (type !== 'Municipality') frm.set_value('municipality', '');
    if (type !== 'Corporation') frm.set_value('corporation', '');
    if (type !== 'Panchayath')   frm.set_value('panchayath', '');
}

