function create_register_from_list(source_doc) {
    frappe.model.with_doctype('Register', function() {

        frappe.db.get_doc('Soil Sample Collection', source_doc.name).then(full_doc => {

            let new_doc = {
                doctype: 'Register',
                __newname: full_doc.name,
                source_sample_id: full_doc.name,
                latitude: full_doc.latitude,
                longitude: full_doc.longitude,
                client_type: full_doc.client_type,
                plot_size: full_doc.plot_size, 
                tests: [],
                crops_list: []
            };

            if (full_doc.tests && full_doc.tests.length > 0) {
                full_doc.tests.forEach(test_row => {
                    new_doc.tests.push({
                        test_name: test_row.test_name
                    });
                });
            }

            if (full_doc.crops_list && full_doc.crops_list.length > 0) {
                full_doc.crops_list.forEach(crop_row => {
                    new_doc.crops_list.push({
                        crop_name: crop_row.crop_name 
                    });
                });
            }

            frappe.db.insert(new_doc).then(doc => {
                frappe.show_alert({
                    message: __("Sample {0} successfully registered", [full_doc.name]),
                    indicator: 'green'
                });
            }).catch(err => {
                console.error("Registration Error: ", err);
                frappe.msgprint({
                    title: __('Registration Failed'),
                    indicator: 'red',
                    message: __('Could not register {0}. It may already exist in the Register.', [full_doc.name])
                });
            });
        });
    });
}

