function filter_variable_inputs(frm, target_id) {
    let grid = frm.fields_dict['variable_inputs'].grid;
    grid.grid_rows.forEach(row => {
        if (row.doc.parent_test_row === target_id) {
            row.wrapper.show();
        } else {
            row.wrapper.hide();
        }
    });
}

function hide_all_variables(frm) {
    let grid = frm.fields_dict['variable_inputs'].grid;
    grid.grid_rows.forEach(row => row.wrapper.hide());
}

