async function calculate_farmer_advice(frm) {
    if (!frm.doc.sample_id) return frappe.msgprint("Please select a Sample ID.");

    try {
        frappe.show_progress(__('Fetching Data'), 20, 100);

        // 1. Get Register
        let register = await frappe.db.get_doc('Register', frm.doc.sample_id);
        if (!register) throw "Register record not found.";

        let plot_size = flt(register.plot_size);
        // CHANGE: Get the full list of crops instead of just the first one
        let crops_list = register.crops_list || [];

        if (crops_list.length === 0 || plot_size <= 0) {
            frappe.hide_progress();
            return frappe.msgprint("Register is missing Crops or Plot Size.");
        }

        frm.clear_table('recommendations_table');

        let results = frm.doc.tests_performed || frm.doc.results_table || []; 

        // 2. OUTER LOOP: Iterate through each Crop in the Register
        for (let crop_row of crops_list) {
            let current_crop = crop_row.crop_name;

            // 3. INNER LOOP: Iterate through each Test Result for this crop
            for (let test of results) {

                // 4. Get PoP Summary for CURRENT crop and nutrient
                let pop_response = await frappe.call({
                    method: "frappe.client.get_value",
                    args: {
                        doctype: "Package of Practice",
                        filters: { crop: current_crop, test_item: test.test_item },
                        fieldname: ["name", "dosage_per_unit", "preferred_fertilizer", "nutrient_percentage"]
                    }
                });

                if (pop_response.message) {
                    let pop_info = pop_response.message;
                    let full_pop = await frappe.db.get_doc('Package of Practice', pop_info.name);

                    if (full_pop && full_pop.rating_table) {
                        let val = flt(test.final_result);
                        let rating = full_pop.rating_table.find(row => 
                            val >= flt(row.min_value) && 
                            val <= (row.max_value === "infinity" ? 999999 : flt(row.max_value))
                        );

                        if (rating) {
                            let dosage = flt(pop_info.dosage_per_unit);
                            let percentage = flt(pop_info.nutrient_percentage);
                            let factor = flt(rating.adjustment_factor);

                            if (dosage > 0 && percentage > 0) {
                                let total_fert = (dosage * factor / percentage) * 100 * plot_size;

                                let row = frm.add_child('recommendations_table');
                                // Added crop name to the table for clarity if you have a 'crop' field
                                if (frm.fields_dict.recommendations_table.grid.docfields.find(df => df.fieldname === 'crop')) {
                                    row.crop = current_crop;
                                }

                                row.nutrient = test.test_item;
                                row.status = rating.rating_label;
                                row.preferred_fertilizer = pop_info.preferred_fertilizer;

                                // Dynamic Note using the current crop name from the loop
                                row.application_note = `Apply ${total_fert.toFixed(2)}g of ${pop_info.preferred_fertilizer} for your ${plot_size} acre ${current_crop} plot.`;

                                row.quantity = total_fert.toFixed(2);
                            }
                        }
                    }
                }
            }
        }

        frappe.show_progress(__('Complete'), 100, 100);
        setTimeout(() => frappe.hide_progress(), 1000);
        frm.refresh_field('recommendations_table');

    } catch (e) {
        console.error(e);
        frappe.hide_progress();
        frappe.msgprint(__("Calculation stopped: " + e.toString()));
    }
}

