// Calculate total and discount
function calculate_amount(frm) {
    let total = 0;

    // Sum up all rates from the child table
    if (frm.doc.tests) {
        frm.doc.tests.forEach(function(row) {
            total += flt(row.rate);
        });
    }

    // Always set the total rate to 'amount_payable'
    frm.set_value("amount_payable", total);

    let discount = flt(frm.doc.discount_percentage);
    let final_payable = total;

    // Calculate discounted rate if applicable
    if (discount > 0) {
        final_payable = total - (total * discount / 100);
    } 

    // Set the discounted rate to 'payable_amount'
    frm.set_value("custom_payable_amount", final_payable);
}

