frappe.ui.form.on('Soil Test Result Entry', { // Change this to the DOCTYPE of your child table
    final_result: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        if (row.test_item && row.final_result !== undefined) {
            frappe.call({
                method: 'frappe.client.get',
                args: {
                    doctype: 'Soil Test Package',
                    name: row.test_item 
                },
                callback: function(r) {
                    if (r.message) {
                        let rules = r.message.rating || []; 
                        let match_found = false;

                        rules.forEach(rule => {
                            let val = flt(row.final_result);
                            let min = flt(rule.min);
                            let max = flt(rule.max);

                            if (val >= min && val <= max) {
                                frappe.model.set_value(cdt, cdn, {
                                    'status': rule.label_eng,
                                    'status_malayalam': rule.label_mal,
                                    'criteria_reference': min + " - " + max
                                });
                                match_found = true;
                            }
                        });

                        if (!match_found) {
                            frappe.model.set_value(cdt, cdn, {
                                'status': 'Out of Range',
                                'status_malayalam': 'പരിധിക്ക് പുറത്താണ്',
                                'criteria_reference': ''
                            });
                        }
                    }
                }
            });
        }
    }
});

