// Main logic for Total and Discount
var calculate_final_price = function(frm) {
    let total = 0;

    // 1. Calculate the base total from child table
    (frm.doc.test_packages || []).forEach(row => {
        total += flt(row.rate);
    });
    frm.set_value('total_amount', total);

    // 2. Calculate the discount
    // Formula: Discount Price = Total - (Total * (Discount / 100))
    let discount_percent = flt(frm.doc.discount);
    let amount_to_deduct = total * (discount_percent / 100);
    let final_price = total - amount_to_deduct;

    // 3. Update the field
    frm.set_value('discount_price', final_price);
};

