// Helper function to perform the math
var calculate_row_result = function(frm, cdt, cdn) {
    let row = locals[cdt][cdn];

    // Ensure both values exist to avoid NaN errors
    if (row.observed_value && row.constantfactor) {

        // Calculation: final_result = observed_value * constantfactor
        let result = flt(row.observed_value) * flt(row.constantfactor);

        // Update the final_result field in the specific row
        frappe.model.set_value(cdt, cdn, 'final_result', result);

        // Automatically run the interpretation logic
        run_interpretation_logic(frm, cdt, cdn, result);
    } else {
        // Reset to 0 if inputs are cleared
        frappe.model.set_value(cdt, cdn, 'final_result', 0);
    }
};

// Interpretation logic based on soil science standards
var run_interpretation_logic = function(frm, cdt, cdn, val) {
    let row = locals[cdt][cdn];
    let status = "";

    // Example logic for Nitrogen (N)
    if (row.test_name === "N") {
        if (val < 280) status = "Low";
        else if (val <= 560) status = "Medium";
        else status = "High";
    } 
    // Example logic for Phosphorus (P)
    else if (row.test_name === "P") {
        if (val < 10) status = "Low";
        else if (val <= 25) status = "Medium";
        else status = "High";
    }

    if (status) {
        frappe.model.set_value(cdt, cdn, 'interpretation', status);
    }
};

