                // Clean up any old variables for this row first
                let old_vars = (frm.doc.variable_inputs || []).filter(v => v.parent_test_row === d.name);
                old_vars.forEach(ov => frappe.model.clear_doc(ov.doctype, ov.name));

                // Add new variables from the Master Soil Test Package
                if (master.variable_table) {
                    master.variable_table.forEach(v => {
                        let var_row = frm.add_child('variable_inputs');
                        var_row.variable_key = v.variable_key;
                        var_row.description = v.label;
                        var_row.parent_test_row = d.name; // THE LINK
                        var_row.test_item = d.test_item;
                    });
                }
                frm.refresh_field('variable_inputs');
                filter_variable_inputs(frm, d.name);
            });
        }
    },

    // Triggered when you click an existing row in the results table
    form_render: function(frm, cdt, cdn) {
