});

// --- PART 2: CALCULATION ENGINE ---
frappe.ui.form.on('Result Variable Value', {
    value: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        let target_id = row.parent_test_row;
        if (!target_id) return;

        // Find the parent test row in the results table
        let test_row = (frm.doc.results_table || []).find(r => r.name === target_id);
        
        if (test_row && test_row.formula) {
            let formula = test_row.formula;
            
            // Get all variables belonging to this specific test row
            let vars = (frm.doc.variable_inputs || []).filter(v => v.parent_test_row === target_id);
            
            // Replace keys with values
            vars.forEach(v => {
                let val = flt(v.value, 4) || 0;
                let regex = new RegExp("\\b" + v.variable_key + "\\b", "g");
                formula = formula.replace(regex, val);
            });

            try {
                // Calculate
                let result = eval(formula);
                
                // Update the final result in the Results Table
                frappe.model.set_value('Soil Test Result Entry', target_id, 'final_result', flt(result, 2));
                
                // Refresh to show the update
                frm.refresh_field('results_table');
            } catch (err) {
                console.error("Math Error:", err);
            }
        }
    }
});

