frappe.ui.form.on('Government Order', {
    refresh: function(frm) {
        // Run the check on load
        toggle_services_visibility(frm);
    },

    // Trigger whenever the GO Name/ID changes
    name: function(frm) {
        toggle_services_visibility(frm);
    }
});

function toggle_services_visibility(frm) {
    if (!frm.doc.name || frm.doc.__islocal) {
        // Hide everything if it's a new unsaved record or empty
        frm.set_df_property('services_and_rates', 'hidden', 1);
        frm.set_df_property('fetch_services', 'hidden', 1);
        return;
    }

    // Call the server to see if this GO has any rates in History
    frappe.call({
        method: "get_services_from_go",
        args: {
            go: frm.doc.name
        },
        callback: function(r) {
            if (r.message && r.message.length > 0) {
                // DATA FOUND: Show the table and the button
                frm.set_df_property('services_and_rates', 'hidden', 0);
                frm.set_df_property('fetch_services', 'hidden', 0);

                // Auto-fill the table if it's currently empty
                if (frm.doc.services_and_rates.length === 0) {
                    fill_table(frm, r.message);
                }
            } else {
                // NO DATA: Keep them hidden
                frm.set_df_property('services_and_rates', 'hidden', 1);
                frm.set_df_property('fetch_services', 'hidden', 1);
            }
        }
    });
}

function fill_table(frm, data) {
    frm.clear_table('services_and_rates');
    data.forEach(d => {
        let row = frm.add_child('services_and_rates');
        row.service = d.service;
        row.service_name = d.service_name;
        row.category = d.category;
        row.rate = d.rate;
        row.effective_from = d.effective_from;
    });
    frm.refresh_field('services_and_rates');

    // Silent save to clear the "Not Saved" flag without refreshing the whole page
    frm.save(); 
}

