frappe.ui.form.on('Soil Test Result', {
    onload: function(frm) {
        hide_all_variables(frm);
        if (frm.doc.sample_id && frm.is_new()) {
            setTimeout(() => {
                frm.trigger('sample_id');
            }, 500);
        }
    },

    refresh: function(frm) {
        frm.add_custom_button(__('Show All Variables'), function() {
            show_all_variables(frm);
        });
        if (!frm.is_new()) {
            hide_all_variables(frm);
        }
    },

    // ── FIX: After save, re-link parent_test_row using test_item as the key ──
    after_save: function(frm) {
        let needs_save = false;

        (frm.doc.variable_inputs || []).forEach(v => {
            // Find the matching results_table row by test_item
            let matching_result_row = (frm.doc.results_table || []).find(
                r => r.test_item === v.test_item
            );
            if (matching_result_row && v.parent_test_row !== matching_result_row.name) {
                v.parent_test_row = matching_result_row.name;
                needs_save = true;
            }
        });

        if (needs_save) {
            // Save silently to persist the corrected parent_test_row links
            frappe.call({
                method: 'frappe.client.save',
                args: { doc: frm.doc },
                callback: function(r) {
                    if (r.message) {
                        frm.doc = r.message;
                        frm.refresh();
                        hide_all_variables(frm);
                        frappe.show_alert({
                            message: 'Test links updated',
                            indicator: 'green'
                        }, 3);
                    }
                }
            });
        }
    },

    sample_id: function(frm) {
        if (!frm.doc.sample_id) return;

        frappe.call({
            method: 'frappe.client.get',
            args: {
                doctype: 'Register',
                name: frm.doc.sample_id
            },
            callback: function(r) {
                if (!r.message || !r.message.tests) return;

                frm.clear_table('results_table');
                frm.clear_table('variable_inputs');
                frm.refresh_field('results_table');
                frm.refresh_field('variable_inputs');

                let fetch_promises = r.message.tests.map(test_row => {
                    return frappe.db.get_doc('Soil Test Package', test_row.test_name).then(master => {
                        if (master.included_tests && master.included_tests.length > 0) {
                            return master.included_tests.map(sub => sub.linked_package);
                        } else {
                            return [test_row.test_name];
                        }
                    });
                });

                Promise.all(fetch_promises).then(results => {
                    let all_test_items = [];
                    results.forEach(items => {
                        items.forEach(item => {
                            if (!all_test_items.includes(item)) {
                                all_test_items.push(item);
                            }
                        });
                    });

                    let master_promises = all_test_items.map(item => {
                        return frappe.db.get_doc('Soil Test Package', item).then(master => {
                            return { item, master };
                        });
                    });

                    Promise.all(master_promises).then(masters_list => {
                        let row_map = {};

                        // Replace this in masters_list.forEach (variable section):
                        masters_list.forEach(({ item, master }) => {
                            let parent_row_name = row_map[item];
                            (master.variable_table || []).forEach(v => {
                                let var_row = frm.add_child('variable_inputs');
                                // Use frappe.model.set_value instead of direct assignment
                                // so values are properly tracked and saved to DB
                                frappe.model.set_value(var_row.doctype, var_row.name, 'variable_key', v.variable_key);
                                frappe.model.set_value(var_row.doctype, var_row.name, 'description', v.label);
                                frappe.model.set_value(var_row.doctype, var_row.name, 'parent_test_row', parent_row_name);
                                frappe.model.set_value(var_row.doctype, var_row.name, 'test_item', item);
                                frappe.model.set_value(var_row.doctype, var_row.name, 'value', v.default_value || '');
                            });
                        });

                        frm.refresh_field('results_table');

                        masters_list.forEach(({ item, master }) => {
                            let parent_row_name = row_map[item];
                            (master.variable_table || []).forEach(v => {
                                let var_row             = frm.add_child('variable_inputs');
                                var_row.variable_key    = v.variable_key;
                                var_row.description     = v.label;
                                var_row.parent_test_row = parent_row_name;
                                var_row.test_item       = item;
                                var_row.value           = v.default_value || '';
                            });
                        });

                        frm.refresh_field('variable_inputs');
                        hide_all_variables(frm);
                    });
                });
            }
        });
    }
});

// ── Child table: results_table row events ──
frappe.ui.form.on('Soil Test Result Entry', {
    form_render: function(frm, cdt, cdn) {
        let d = locals[cdt][cdn];

        // ── Highlight selected row, remove highlight from others ──
        frm.fields_dict['results_table'].grid.grid_rows.forEach(row => {
            if (row.doc.name === d.name) {
                $(row.wrapper).css('background-color', 'var(--yellow-highlight-color, #fffbe6)');
            } else {
                $(row.wrapper).css('background-color', '');
            }
        });

        setTimeout(() => {
            filter_variable_inputs(frm, d.name);
        }, 100);
    },

    test_item: function(frm, cdt, cdn) {
        let d = locals[cdt][cdn];
        if (!d.test_item) return;

        frappe.db.get_doc('Soil Test Package', d.test_item).then(master => {
            if (master.included_tests && master.included_tests.length > 0) {
                master.included_tests.forEach(sub => {
                    let exists = (frm.doc.results_table || []).some(
                        r => r.test_item === sub.linked_package && r.name !== cdn
                    );
                    if (!exists) {
                        let new_row       = frm.add_child('results_table');
                        new_row.test_item = sub.linked_package;
                    }
                });
                frm.doc.results_table = (frm.doc.results_table || []).filter(r => r.name !== cdn);
                frm.refresh_field('results_table');
                return;
            }

            frappe.model.set_value(cdt, cdn, 'formula', master.formula);
            frappe.model.set_value(cdt, cdn, 'unit', master.target_unit);

            let names_to_remove = (frm.doc.variable_inputs || [])
                .filter(v => v.parent_test_row === d.name)
                .map(v => v.name);
            names_to_remove.forEach(name => {
                let idx = (frm.doc.variable_inputs || []).findIndex(v => v.name === name);
                if (idx !== -1) frm.doc.variable_inputs.splice(idx, 1);
            });

            (master.variable_table || []).forEach(v => {
                let var_row             = frm.add_child('variable_inputs');
                var_row.variable_key    = v.variable_key;
                var_row.description     = v.label;
                var_row.parent_test_row = d.name;
                var_row.test_item       = d.test_item;
                var_row.value           = v.default_value || '';
            });

            frm.refresh_field('variable_inputs');
            filter_variable_inputs(frm, d.name);
        });
    }
});

// ── Calculation engine ──
frappe.ui.form.on('Result Variable Value', {
    value: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        let target_id = row.parent_test_row;
        if (!target_id) return;

        let test_row = (frm.doc.results_table || []).find(r => r.name === target_id);
        if (!test_row || !test_row.formula) return;

        let formula = test_row.formula;

        // Strictly filter by parent_test_row only — no test_item fallback needed
        let vars = (frm.doc.variable_inputs || []).filter(
            v => v.parent_test_row === target_id
        );

        if (!vars.length) return;

        vars.forEach(v => {
            let val   = flt(v.value, 4) || 0;
            let regex = new RegExp("\\b" + v.variable_key + "\\b", "g");
            formula   = formula.replace(regex, val);
        });

        try {
            let result = eval(formula);
            frappe.model.set_value(
                'Soil Test Result Entry',
                test_row.name,
                'final_result',
                flt(result, 2)
            );
            frm.refresh_field('results_table');
        } catch (err) {
            console.error("Formula Error:", err, "Formula was:", formula);
        }
    }
});


// ── Helper functions ──
function filter_variable_inputs(frm, target_id) {
    let grid  = frm.fields_dict['variable_inputs'].grid;
    let found = false;

    (grid.grid_rows || []).forEach(row => {
        if (row.doc.parent_test_row === target_id) {
            $(row.wrapper).show();
            found = true;
        } else {
            $(row.wrapper).hide();
        }
    });

    if (found) {
        frm.fields_dict['variable_inputs'].$wrapper[0].scrollIntoView({
            behavior: 'smooth',
            block: 'nearest'
        });
    }
}

function hide_all_variables(frm) {
    (frm.fields_dict['variable_inputs'].grid.grid_rows || []).forEach(row => {
        $(row.wrapper).hide();
    });
}

function show_all_variables(frm) {
    (frm.fields_dict['variable_inputs'].grid.grid_rows || []).forEach(row => {
        $(row.wrapper).show();
    });
}

